1	// claim-office.spec.ts
2	import { describe, it, expect } from "vitest";
3	import { runScenario } from "./claim-office.js";
4	
5	describe("MHPCO Claim Office", () => {
6	  describe("Premium calculation (quote)", () => {
7	    it("should return premium 5 for an empty item list (processing fee only)", () => {
8	      const result = runScenario({
9	        customer: { yearsWithMHPCO: 0 },
10	        steps: [{ op: "quote", items: [] }],
11	      });
12	
13	      expect(result.results[0].premium).toBe(5);
14	    });
15	    it.todo("should quote a single sword at base premium 100 (plus first-insurance surcharge and fee)");
16	    it.todo("should use base premiums amulet 60, staff 80, potion 40");
17	    it.todo("should charge 25 per component: 2 runes give base premium 50");
18	    it.todo("should apply the block premium 60 for exactly 3 alike components: 3 runes give base premium 60");
19	    it.todo("should not apply the block to 4 alike components: 4 runes give base premium 100");
20	    it.todo("should price 7 runes at base premium 175");
21	    it.todo("should not form a block from different component types: 2 runes + 1 moonstone give base premium 75");
22	    it.todo("should form one block per component type: 3 runes + 3 moonstones give base premium 120");
23	    it.todo("should add 50% of the item base premium for a cursed item");
24	    it.todo("should add 30% of the item base premium for enchantment level exactly 5");
25	    it.todo("should not add the enchantment surcharge for enchantment level 4");
26	    it.todo("should stack curse and enchantment surcharges on one item");
27	    it.todo("should apply the cursed surcharge only to the cursed item's base premium: cursed sword + plain amulet give 210 before policy modifiers and fee");
28	    it.todo("should apply the 20% loyalty discount for yearsWithMHPCO exactly 2");
29	    it.todo("should apply the 10% first-insurance surcharge to every quote");
30	    it.todo("should apply the 15% follow-up discount to each quote after the first");
31	    it.todo("should round the final premium up to whole gold (197.5 becomes 198)");
32	    it.todo("should quote 165 for a newcomer (0 years) with a cursed steel sword of enchantment 3");
33	    it.todo("should quote 160 for a 3-year customer's second quote with a cursed sword of enchantment 7");
34	  });
35	
36	  describe("Claim payout", () => {
37	    it.todo("should subtract the 100 deductible from the damage amount: regular sword (enchantment 3) damaged 500 pays out 400");
38	    it.todo("should apply the deductible per damaged item, not per incident: sword 500 + amulet 300 pay out 600");
39	    it.todo("should reimburse 50% of the damage for enchantment level 9 or higher than 8 (steel sword enchantment 9), before the deductible");
40	    it.todo("should reimburse dragon-material items in full: dragon sword enchantment 5 gets full reimbursement");
41	    it.todo("should let the 50% rule win when dragon material and enchantment 8 combine: dragon sword enchantment exactly 8, damage 1000 pays out 400");
42	    it.todo("should treat components as having no enchantment or material: rune damaged 200 pays out 100");
43	    it.todo("should return remainingCap as 2x the insurance sum minus payouts: sword + amulet have insurance sum 1600 and cap 3200");
44	    it.todo("should keep the insurance sum unmodified by the block discount: sword + 3 runes have insurance sum 1750");
45	    it.todo("should sum same-type items into the insurance sum: two swords have insurance sum 2000 and cap 4000");
46	    it.todo("should consume the cap across successive claims: sword (cap 2000) with two claims of 1500 pays 1400 then 600");
47	    it.todo("should round the final payout down to whole gold (350.5 becomes 350)");
48	    it.todo("should apply a separate deductible per damage entry for two insured swords");
49	  });
50	
51	  describe("Errors", () => {
52	    it.todo("should reject a quote containing an unknown item type (broomstick)");
53	    it.todo("should reject a claim damage entry whose item type is not in the policy (amulet damaged, only sword insured)");
54	    it.todo("should reject a claim with more damage entries of a type than items insured (two sword damages, one sword insured)");
55	    it.todo("should reject a claim damage entry with an unknown item type");
56	    it.todo("should reject a negative damage amount");
57	  });
58	
59	  describe("CLI", () => {
60	    it.todo("should read a JSON scenario from stdin and write {results: [...]} to stdout with exit code 0");
61	    it.todo("should exit non-zero with the error on stderr and no results on stdout for an invalid scenario");
62	  });
63	});
64

1	type Scenario = {
2	  customer: { yearsWithMHPCO: number };
3	  steps: { op: "quote"; items: unknown[] }[];
4	};
5	
6	type ScenarioResult = {
7	  results: { premium: number }[];
8	};
9	
10	const PROCESSING_FEE = 5;
11	
12	export const runScenario = (scenario: Scenario): ScenarioResult => {
13	  return { results: [{ premium: PROCESSING_FEE }] };
14	};
